import{c as a,Q as t,j as l,m as o}from"./chunks/framework.BXc4yaFE.js";const b=JSON.parse('{"title":"Claude Code Onboarding 與大型 Codebase 最佳實踐","description":"","frontmatter":{"title":"Claude Code Onboarding 與大型 Codebase 最佳實踐","source":"Anthropic 官方","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/29-onboarding-large-codebase.md","filePath":"research/best-practices/29-onboarding-large-codebase.md","lastUpdated":1779935873000}'),s={name:"research/best-practices/29-onboarding-large-codebase.md"};function r(i,e,d,n,c,p){return t(),l("div",null,[...e[0]||(e[0]=[o(`<h1 id="claude-code-onboarding-與大型-codebase-最佳實踐" tabindex="-1">Claude Code Onboarding 與大型 Codebase 最佳實踐 <a class="header-anchor" href="#claude-code-onboarding-與大型-codebase-最佳實踐" aria-label="Permalink to &quot;Claude Code Onboarding 與大型 Codebase 最佳實踐&quot;">​</a></h1><blockquote><p>來源 1：<a href="https://claude.com/blog/onboarding-claude-code-like-a-new-developer-lessons-from-17-years-of-development" target="_blank" rel="noreferrer">https://claude.com/blog/onboarding-claude-code-like-a-new-developer-lessons-from-17-years-of-development</a><br> 作者：Brendan MacLean（Claude Developer Ambassador，MacCoss Lab / Univ. of Washington）<br> 來源 2：<a href="https://claude.com/blog/how-claude-code-works-in-large-codebases-best-practices-and-where-to-start" target="_blank" rel="noreferrer">https://claude.com/blog/how-claude-code-works-in-large-codebases-best-practices-and-where-to-start</a><br> 發布：2026-05-14，Anthropic 官方<br> 收錄日期：2026-05-16<br> 重要性：★★★（大型 codebase 導入 Claude Code 的基礎架構藍圖）</p></blockquote><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><p>「不要把 70 萬行程式碼丟給新人，然後期待立刻有成果。Claude 也一樣。」</p><p>成功導入 Claude Code 的組織，共同特徵是將 <strong>context 視為需要維護的工件</strong>——版本化、分層、持續更新。</p><hr><h2 id="一、skyline-案例-17-年開發積累-vs-claude-學習曲線" tabindex="-1">一、Skyline 案例：17 年開發積累 vs. Claude 學習曲線 <a class="header-anchor" href="#一、skyline-案例-17-年開發積累-vs-claude-學習曲線" aria-label="Permalink to &quot;一、Skyline 案例：17 年開發積累 vs. Claude 學習曲線&quot;">​</a></h2><p><strong>背景</strong>：MacCoss Lab 維護 Skyline（蛋白質分析軟體），70 萬行 C#，2008 年起開發，20 萬+ 自動化夜間測試，歷經數十位開發者 Onboarding。</p><p><strong>核心策略</strong>：將人員 Onboarding 方法論直接套用到 Claude：</p><ul><li>不期望 Claude 立刻理解整個 codebase</li><li>先從小型獨立模組開始建立理解</li><li>逐步擴大範圍，同時保持專屬 context</li></ul><p><strong>成果</strong>：</p><ul><li>原本一年的 Files View 面板專案 → <strong>兩週完成</strong></li><li>2,000+ 教程截圖自動更新</li><li>每日基礎設施摘要自動生成</li><li>原本抗拒的團隊成員也開始成功交付功能</li></ul><hr><h2 id="二、三層-context-架構" tabindex="-1">二、三層 Context 架構 <a class="header-anchor" href="#二、三層-context-架構" aria-label="Permalink to &quot;二、三層 Context 架構&quot;">​</a></h2><h3 id="層-1-context-repository-獨立-git-repo" tabindex="-1">層 1：Context Repository（獨立 Git Repo） <a class="header-anchor" href="#層-1-context-repository-獨立-git-repo" aria-label="Permalink to &quot;層 1：Context Repository（獨立 Git Repo）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pwiz-ai/                        # 獨立 context repository</span></span>
<span class="line"><span>├── CLAUDE.md                   # 根目錄：方向 + 文件索引</span></span>
<span class="line"><span>├── skills/</span></span>
<span class="line"><span>│   ├── skyline-development.md  # 領域知識 Skill</span></span>
<span class="line"><span>│   ├── version-control.md      # 版本控制流程</span></span>
<span class="line"><span>│   └── debugging.md            # 除錯流程</span></span>
<span class="line"><span>└── docs/</span></span>
<span class="line"><span>    └── architecture.md         # 架構概覽</span></span></code></pre></div><p><strong>關鍵設計</strong>：</p><ul><li>適用所有 branch 和開發時間點</li><li>「參考不嵌入」原則：Skills 指向文件，而非複製內容</li><li>明確的觸發條件（什麼時候呼叫這個 Skill）</li></ul><h3 id="層-2-skills-library-可重用領域知識" tabindex="-1">層 2：Skills Library（可重用領域知識） <a class="header-anchor" href="#層-2-skills-library-可重用領域知識" aria-label="Permalink to &quot;層 2：Skills Library（可重用領域知識）&quot;">​</a></h3><ul><li>將機構知識編碼為可跨 session 使用的 Skill</li><li>每個 Skill 有明確的觸發條件</li><li>Critical skills 有顯式觸發條件（防止遺漏）</li></ul><h3 id="層-3-mcp-整合-實時資料接取" tabindex="-1">層 3：MCP 整合（實時資料接取） <a class="header-anchor" href="#層-3-mcp-整合-實時資料接取" aria-label="Permalink to &quot;層 3：MCP 整合（實時資料接取）&quot;">​</a></h3><p>MacCoss Lab 用 C# 和 Python 撰寫 MCP Server（由 Claude 自己撰寫），連接：</p><ul><li>自動化測試結果</li><li>異常報告</li><li>技術支援帖（Historical Issues）</li></ul><p><strong>原則</strong>：「真實資訊勝過抽象知識」——MCP 讓 Claude 查到真實的測試失敗，而非猜測。</p><hr><h2 id="三、大型-codebase-導入-官方建議" tabindex="-1">三、大型 Codebase 導入：官方建議 <a class="header-anchor" href="#三、大型-codebase-導入-官方建議" aria-label="Permalink to &quot;三、大型 Codebase 導入：官方建議&quot;">​</a></h2><p>來源：Anthropic 官方（2026-05-14）</p><h3 id="claude-code-的導覽方式" tabindex="-1">Claude Code 的導覽方式 <a class="header-anchor" href="#claude-code-的導覽方式" aria-label="Permalink to &quot;Claude Code 的導覽方式&quot;">​</a></h3><p>Claude Code 使用 <strong>Agentic Search</strong>（非 RAG/embedding）：</p><ul><li>直接在本地 codebase traverse，使用類 grep 導覽</li><li>優勢：永遠是最新代碼（無過時 embedding index）</li><li>要求：codebase 組織良好，否則導覽效率低</li></ul><p><strong>實際意涵</strong>：好的 codebase 結構本身就是提升 Claude Code 效果的槓桿。</p><h3 id="五元件-harness-生態系統" tabindex="-1">五元件 Harness 生態系統 <a class="header-anchor" href="#五元件-harness-生態系統" aria-label="Permalink to &quot;五元件 Harness 生態系統&quot;">​</a></h3><p>成功的大型 codebase 導入依賴五元件組合：</p><table tabindex="0"><thead><tr><th>元件</th><th>功能</th><th>設計原則</th></tr></thead><tbody><tr><td>CLAUDE.md</td><td>每 session 自動載入的 context</td><td>精簡、分層（按目錄）、排除生成檔案</td></tr><tr><td>Hooks</td><td>事件觸發的自動化腳本</td><td>用於持續改進和自動化</td></tr><tr><td>Skills</td><td>按需載入的專業知識</td><td>特定任務類型的打包專業知識</td></tr><tr><td>Plugins</td><td>跨組織分發的設定包</td><td>統一組織內 Claude Code 設定</td></tr><tr><td>MCP Servers</td><td>連接內部工具和 API</td><td>讓 Claude 存取真實的內部資料</td></tr></tbody></table><p><strong>加分項</strong>：LSP（Language Server Protocol）整合，提供符號級搜尋導覽。</p><h3 id="claude-md-三大設定原則" tabindex="-1">CLAUDE.md 三大設定原則 <a class="header-anchor" href="#claude-md-三大設定原則" aria-label="Permalink to &quot;CLAUDE.md 三大設定原則&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 保持精簡（lean）：大型 codebase 不等於長 CLAUDE.md</span></span>
<span class="line"><span>2. 子目錄初始化：每個子系統有自己的 CLAUDE.md，範疇化指令</span></span>
<span class="line"><span>3. 排除生成檔案：告訴 Claude 哪些目錄是自動生成的，避免誤讀</span></span></code></pre></div><h3 id="三個設定模式" tabindex="-1">三個設定模式 <a class="header-anchor" href="#三個設定模式" aria-label="Permalink to &quot;三個設定模式&quot;">​</a></h3><p><strong>模式 A：讓 Codebase 可導覽</strong></p><ul><li>CLAUDE.md 保持精簡，按目錄初始化</li><li>子目錄 Commands 按範疇設定</li><li>排除生成檔案、執行 LSP server 做符號搜尋</li></ul><p><strong>模式 B：主動維護設定</strong></p><ul><li>每 3-6 個月審閱設定（模型進化，舊指令可能反而限制新模型）</li><li>隨模型能力提升逐步移除過時約束</li><li>建立設定版本追蹤</li></ul><p><strong>模式 C：組織所有權</strong></p><ul><li>指定 DRI（Directly Responsible Individual）管理 Claude Code 設定</li><li>建立跨職能工作組（工程 + 安全 + 治理）</li><li>防止設定碎片化，確保跨組織一致性</li></ul><hr><h2 id="四、對-workspace-設計的啟示" tabindex="-1">四、對 workspace 設計的啟示 <a class="header-anchor" href="#四、對-workspace-設計的啟示" aria-label="Permalink to &quot;四、對 workspace 設計的啟示&quot;">​</a></h2><h3 id="現有-cc-workspace-的對應" tabindex="-1">現有 cc-workspace 的對應 <a class="header-anchor" href="#現有-cc-workspace-的對應" aria-label="Permalink to &quot;現有 cc-workspace 的對應&quot;">​</a></h3><table tabindex="0"><thead><tr><th>本文建議</th><th>workspace 現狀</th></tr></thead><tbody><tr><td>獨立 context repository</td><td><code>.claude/</code> 目錄（Skill、rules、refs 分層）</td></tr><tr><td>CLAUDE.md 精簡分層</td><td>CLAUDE.md ≤ 200 行 + @rules 載入</td></tr><tr><td>Skills Library</td><td><code>.claude/skills/</code></td></tr><tr><td>MCP 整合</td><td>settings.json MCP 設定</td></tr><tr><td>每 3-6 個月審閱</td><td>尚未設定定期審閱機制 ← 建議加入</td></tr><tr><td>DRI 所有權</td><td>個人 workspace，單一 owner</td></tr></tbody></table><h3 id="建議新增" tabindex="-1">建議新增 <a class="header-anchor" href="#建議新增" aria-label="Permalink to &quot;建議新增&quot;">​</a></h3><ol><li><strong>定期 Context 健康審閱</strong>：每季執行 <code>research-hub:audit</code>，評估設定是否仍符合當前模型能力</li><li><strong>Skills 觸發條件文件化</strong>：每個 Skill 加入明確的觸發/排除條件（現有 skills 大多已有，需持續維護）</li><li><strong>MCP 真實資料接入</strong>：優先接入會頻繁查詢的內部資料（如 git log、test results）</li></ol><hr><h2 id="五、隊友-onboarding-team-onboarding-w15-v2-1-101" tabindex="-1">五、隊友 Onboarding：/team-onboarding（W15，v2.1.101） <a class="header-anchor" href="#五、隊友-onboarding-team-onboarding-w15-v2-1-101" aria-label="Permalink to &quot;五、隊友 Onboarding：/team-onboarding（W15，v2.1.101）&quot;">​</a></h2><p>根據本地 Claude Code 使用紀錄自動生成新成員 onboarding 指南，讓隊友可以沿用你已調好的工作流設定，而非從預設值重新摸索。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /team-onboarding</span></span></code></pre></div><p>生成內容涵蓋：你的 CLAUDE.md 設定慣例、常用 Skills、Hooks 配置、以及 session 中記錄的工作流偏好。輸出可直接分享或提交進 context repository。</p><hr><h2 id="快速-checklist" tabindex="-1">快速 Checklist <a class="header-anchor" href="#快速-checklist" aria-label="Permalink to &quot;快速 Checklist&quot;">​</a></h2><h3 id="初次設定" tabindex="-1">初次設定 <a class="header-anchor" href="#初次設定" aria-label="Permalink to &quot;初次設定&quot;">​</a></h3><ul><li>[ ] 建立 context repository 或獨立 context 目錄</li><li>[ ] 根目錄 CLAUDE.md：方向 + 文件索引（≤ 200 行）</li><li>[ ] 子目錄各有各的 CLAUDE.md（範疇化指令）</li><li>[ ] 排除生成檔案目錄（build/、dist/、<em>.generated.</em>)</li><li>[ ] 核心領域知識編碼為 Skills</li></ul><h3 id="持續維護" tabindex="-1">持續維護 <a class="header-anchor" href="#持續維護" aria-label="Permalink to &quot;持續維護&quot;">​</a></h3><ul><li>[ ] 每 3-6 個月審閱 CLAUDE.md 和 Skills（模型進化後重新評估）</li><li>[ ] 新知識加入 Skills（不只是即時對話）</li><li>[ ] MCP 接入高頻查詢的內部資料</li><li>[ ] Cache hit rate 監控（ref: 28-thariq-prompt-caching-lessons.md）</li><li>[ ] 有新成員加入時執行 <code>/team-onboarding</code> 生成 onboarding 指南</li></ul><blockquote><p>一手來源（O 層）：Anthropic 官方 blog + Claude Developer Ambassador 案例</p></blockquote>`,63)])])}const u=a(s,[["render",r]]);export{b as __pageData,u as default};
